events.onBlur:
const name = String(ctx.value || '').trim();
await ctx.setValue('客户名称', name);
ctx.setValue('状态提示', name ? `当前客户：${name}` : '请先填写客户名称。');

events.onChange:
const issueType = String(ctx.value || '');
const row = ctx.querySheet('issue_catalog').find((item) => item?.问题类型 === issueType);
await ctx.setValue('问题类型', issueType);
await ctx.setValue('处理人', row?.默认处理人 || '');
ctx.setValue('状态提示', issueType ? `已按问题类型分配处理人：${row?.默认处理人 || '待人工确认'}` : '请选择问题类型。');

events.onClick:
const customer = String(ctx.getValue('客户名称') || '').trim();
const issueType = String(ctx.getValue('问题类型') || '').trim();
if (!customer) return ctx.showMessage('请填写客户名称', 'error');
if (!issueType) return ctx.showMessage('请选择问题类型', 'error');
let currentId = Number(ctx.getValue('工单ID') || 0);
if (!currentId) {
  const rows = ctx.querySheet('service_tickets');
  currentId = rows.reduce((max, row) => Math.max(max, Number(row?.工单ID) || 0), 0) + 1;
  await ctx.setValue('工单ID', currentId);
}
if (!ctx.getValue('状态')) await ctx.setValue('状态', '待分派');
if (!ctx.getValue('创建日期')) await ctx.setValue('创建日期', '2026-07-06');
await ctx.runConfiguredWorkflow();
await ctx.setValue('工单ID', currentId + 1);
await ctx.setValue('客户名称', '');
await ctx.setValue('问题类型', '');
await ctx.setValue('优先级', '中');
await ctx.setValue('状态', '待分派');
await ctx.setValue('处理人', '');
await ctx.setValue('处理说明', '');
await ctx.setValue('创建日期', '2026-07-06');
ctx.setValue('状态提示', `工单 ${currentId} 已创建，可继续录入下一条。`);
await ctx.showMessage(`工单 ${currentId} 已创建`, 'success');

const rows = ctx.querySheet('service_tickets');
const maxId = rows.reduce((max, row) => Math.max(max, Number(row?.工单ID) || 0), 0);
await ctx.setValue('工单ID', maxId + 1);
await ctx.setValue('客户名称', '');
await ctx.setValue('问题类型', '');
await ctx.setValue('优先级', '中');
await ctx.setValue('状态', '待分派');
await ctx.setValue('处理人', '');
await ctx.setValue('处理说明', '');
ctx.setValue('状态提示', '表单已重置，可录入新的服务工单。');
